+  const { data: liveData, isLoading, isRefreshing, isFailed, consecutiveFailures, isDemoFallback, lastRefresh } =
     useCache<FluentdStatus>({
       key: CACHE_KEY,
       category: 'default',
@@ -341,5 +346,6 @@ export function useFluentdStatus(): UseFluentdStatusResult {
